    PLACEMARKSVectorOffset PLACEMARKS: Offset = Offset(),
    FOLDERSVectorOffset FOLDERS: Offset = Offset(),
    NETWORK_LINKSVectorOffset NETWORK_LINKS: Offset = Offset(),
    GROUND_OVERLAYSVectorOffset GROUND_OVERLAYS: Offset = Offset(),
